package com.enterprise.auth.service;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Service;

@Service
public class RecoveryCodeService {

    @Autowired
    private UserRepository userRepository;

    public List<String> generateRecoveryCodes(UserDetails userDetails) {
        User user = userRepository.findByUsername(userDetails.getUsername());
        List<String> recoveryCodes = new ArrayList<>();
        for (int i = 0; i < 10; i++) { // Generate 10 recovery codes
            String code = generateRandomCode();
            recoveryCodes.add(code);
        }
        user.setRecoveryCodes(recoveryCodes);
        userRepository.save(user);
        return recoveryCodes;
    }

    private String generateRandomCode() {
        SecureRandom random = new SecureRandom();
        StringBuilder sb = new StringBuilder(10);
        for (int i = 0; i < 10; i++) {
            int number = random.nextInt(36); // Generates a number between 0 and 35
            char character = (char) (number < 26 ? 'A' + number : '2' + (number - 26));
            sb.append(character);
        }
        return sb.toString();
    }

    public boolean authenticateWithRecoveryCode(String username, String recoveryCode) {
        User user = userRepository.findByUsername(username);
        if (user != null && user.getRecoveryCodes().contains(recoveryCode)) {
            user.getRecoveryCodes().remove(recoveryCode); // Remove used code
            userRepository.save(user);
            return true;
        }
        return false;
    }

    @Autowired
    private PasswordEncoder passwordEncoder;

    public boolean enable2FA(UserDetails userDetails, String secret) {
        User user = userRepository.findByUsername(userDetails.getUsername());
        if (user != null) {
            user.setTwoFactorAuthenticationEnabled(true);
            user.setSecret(secret);
            userRepository.save(user);
            return true;
        }
        return false;
    }

    public boolean is2FAEnabled(UserDetails userDetails) {
        User user = userRepository.findByUsername(userDetails.getUsername());
        return user != null && user.isTwoFactorAuthenticationEnabled();
    }
}